// ============================================================
// Workflow JavaScript Action — Hourly BizEvents Demo Injector
// ============================================================
// HOW TO USE
//   1. Find every [REPLACE_...] token and substitute your values.
//   2. Adjust TUNABLES to match expected production volumes.
//   3. Extend / remove event generators (sections 1–5) to match
//      the customer's actual business processes.
//   4. Import this workflow into Dynatrace Automations.
//      The workflow runs every 60 minutes using integrated auth.
//
// TOKEN REFERENCE
//   [REPLACE_CLIENT_NAME]       e.g. "Acme Corp"
//   [REPLACE_EVENT_PROVIDER]    e.g. "acme.event.provider"
//   [REPLACE_REGION_1..N]       Production region names
//   [REPLACE_LOCATION_1..N]     City / data-centre names
//   [REPLACE_PRODUCT_1..N]      Core product / service names
//   [REPLACE_CHANNEL_1..N]      Customer-facing channels
//   [REPLACE_SEGMENT_1..N]      Customer or account segments
//
// DIURNAL TRAFFIC MODEL (built-in)
//   Volume scales by UTC hour to avoid flat "robot" charts.
//   Adjust TIMEZONE_OFFSET_HOURS to shift peak to local business hours.
//   Weekend dampening is applied automatically (0 = Sunday).

export default async function () {

  // ─── TUNABLES ────────────────────────────────────────────────────────────
  const HOURS_WINDOW   = 1;    // window covered per run (keep at 1)
  const CHUNK          = 500;  // events per ingest request (keep ≤ 500)

  // Peak-hour volumes (diurnal model scales these down during off-hours)
  const TXN_MIN        = 600;   // [REPLACE] primary transaction floor
  const TXN_MAX        = 1000;  // [REPLACE] primary transaction ceiling
  const ORDER_MIN      = 50;    // [REPLACE] secondary event floor
  const ORDER_MAX      = 150;   // [REPLACE] secondary event ceiling
  const ALERT_MIN      = 5;     // [REPLACE] platform alert floor
  const ALERT_MAX      = 15;    // [REPLACE] platform alert ceiling
  const ERROR_RATE     = 0.02;  // [REPLACE] system error fraction (0.0–1.0)
  const DECLINE_RATE   = 0.03;  // [REPLACE] business decline/reject fraction

  // Shift peak to local business hours. UTC offset of customer HQ:
  //   London = 0 (summer) / -1 (winter), US Eastern = -5/-4, APAC SGT = +8
  const TIMEZONE_OFFSET_HOURS = 0; // [REPLACE]

  // ─── IDENTITY ────────────────────────────────────────────────────────────
  const CLIENT_NAME    = "[REPLACE_CLIENT_NAME]";
  const EVENT_PROVIDER = "[REPLACE_EVENT_PROVIDER]";

  // ─── ENVIRONMENTS ────────────────────────────────────────────────────────
  // Add/remove rows to match the customer's production footprint.
  const ENVIRONMENTS = [
    { name: "[REPLACE_REGION_1]", location: "[REPLACE_LOCATION_1]", lat: 0.0, lon: 0.0 },
    { name: "[REPLACE_REGION_2]", location: "[REPLACE_LOCATION_2]", lat: 0.0, lon: 0.0 },
  ];
  // Relative traffic weight per environment (must match ENVIRONMENTS length)
  const ENV_WEIGHTS = [0.60, 0.40];

  // ─── DIMENSIONS ──────────────────────────────────────────────────────────
  const PRODUCTS    = ["[REPLACE_PRODUCT_1]", "[REPLACE_PRODUCT_2]", "[REPLACE_PRODUCT_3]"];
  const PROD_WEIGHTS = [0.50, 0.30, 0.20];

  const CHANNELS    = ["[REPLACE_CHANNEL_1]", "[REPLACE_CHANNEL_2]", "[REPLACE_CHANNEL_3]"];
  const CHAN_WEIGHTS = [0.50, 0.35, 0.15];

  const SEGMENTS    = ["[REPLACE_SEGMENT_1]", "[REPLACE_SEGMENT_2]", "[REPLACE_SEGMENT_3]"];
  const SEG_WEIGHTS = [0.60, 0.30, 0.10];

  // Failure reasons — customise to match the domain
  const BIZ_DECLINE_REASONS = ["INSUFFICIENT_FUNDS", "VALIDATION_FAILED", "LIMIT_EXCEEDED", "DO_NOT_HONOR"];
  const BIZ_DECLINE_WEIGHTS  = [0.35, 0.25, 0.25, 0.15];
  const SYS_ERROR_REASONS    = ["TIMEOUT", "SERVICE_UNAVAILABLE", "INTERNAL_ERROR"];

  // Platform/infrastructure alert types
  const ALERT_TYPES    = ["latency_spike", "error_rate_increase", "connection_pool", "memory_pressure", "queue_depth", "circuit_breaker"];
  const ALERT_WEIGHTS  = [0.28, 0.22, 0.18, 0.14, 0.10, 0.08];
  const SEVERITIES     = ["critical", "high", "medium", "low"];
  const SEV_WEIGHTS    = [0.05, 0.15, 0.40, 0.40];

  // Service components (4–5 per transaction, models blast-radius risk)
  const COMPONENTS = ["api_gateway", "auth_service", "core_processor", "data_store", "downstream_connector"];

  // ─── DIURNAL MODEL ───────────────────────────────────────────────────────
  // Returns a 0.0–1.0 volume multiplier for a given local hour.
  // Shape: low overnight, ramp 07–09, peak 10–17, taper 18–22.
  function diurnalMultiplier(utcH, isWeekend) {
    const localH = ((utcH + TIMEZONE_OFFSET_HOURS) % 24 + 24) % 24;
    const CURVE = [
      0.25, 0.20, 0.18, 0.20,   // 00–03
      0.28, 0.38, 0.55, 0.70,   // 04–07
      0.82, 0.90, 0.95, 0.98,   // 08–11
      1.00, 1.00, 0.98, 0.95,   // 12–15  ← peak
      0.90, 0.82, 0.70, 0.60,   // 16–19
      0.50, 0.42, 0.35, 0.28    // 20–23
    ];
    const base = CURVE[Math.max(0, Math.min(23, localH))];
    return isWeekend ? base * 0.65 : base;
  }

  // ─── GENERIC HELPERS ─────────────────────────────────────────────────────
  function nowUtc()   { return new Date(); }
  function toIso(d)   { return new Date(d).toISOString(); }
  function clampFuture(ts, now, safetyS) {
    const max = new Date(now.getTime() - safetyS * 1000);
    return ts > max ? max : ts;
  }
  function randInt(min, max)   { return Math.floor(Math.random() * (max - min + 1)) + min; }
  function randFloat(min, max) { return Math.random() * (max - min) + min; }
  function choose(arr)         { return arr[Math.floor(Math.random() * arr.length)]; }
  function chooseWeighted(opts, wts) {
    const total = wts.reduce((a, b) => a + b, 0);
    const w = wts.map(v => v / (total || 1));
    const r = Math.random();
    let acc = 0;
    for (let i = 0; i < opts.length; i++) { acc += w[i]; if (r <= acc) return opts[i]; }
    return opts[opts.length - 1];
  }
  // Spreads `count` timestamps evenly across [start,end] with ±jitter fraction
  function distribute(start, end, count, jitter) {
    const spanMs = end.getTime() - start.getTime();
    const stepMs = Math.max(1, Math.floor(spanMs / Math.max(1, count)));
    const out = [];
    for (let i = 0; i < count; i++) {
      const base = new Date(start.getTime() + i * stepMs);
      const jms  = Math.floor((Math.random() * 2 * jitter - jitter) * stepMs);
      out.push(new Date(base.getTime() + jms));
    }
    return out;
  }
  function makeEvent(provider, etype, ts, extra, now) {
    const safeTs = clampFuture(ts, now, 30);
    const ev = { "event.provider": provider, "event.type": etype, "timestamp": toIso(safeTs) };
    if (extra && typeof extra === "object") Object.assign(ev, extra);
    return ev;
  }
  function countBy(arr, fn) {
    const m = {};
    for (const x of arr) { const k = fn(x); m[k] = (m[k] || 0) + 1; }
    return m;
  }
  function afterMs(dt, ms) { return new Date(dt.getTime() + ms); }
  function randomId(prefix, len) {
    const hex = "abcdef0123456789";
    let s = "";
    for (let i = 0; i < len; i++) s += hex[Math.floor(Math.random() * hex.length)];
    return prefix + s.toUpperCase();
  }

  // ─── TIME CONTEXT ────────────────────────────────────────────────────────
  const now      = nowUtc();
  const start    = new Date(now.getTime() - HOURS_WINDOW * 3600000);
  const utcH     = now.getUTCHours();
  const utcDay   = now.getUTCDay();
  const isWeekend = utcDay === 0 || utcDay === 6;
  const dayNames  = ["sunday","monday","tuesday","wednesday","thursday","friday","saturday"];
  const dayName   = dayNames[utcDay];
  const DIURNAL   = diurnalMultiplier(utcH, isWeekend);

  // Latency increases at peak load (queuing effect)
  const loadFactor = DIURNAL > 0.90 ? 1.20 : (DIURNAL > 0.75 ? 1.08 : 1.0);
  // Overnight: slightly higher failure rate (fewer support staff)
  const effectiveDeclineRate = DECLINE_RATE * (utcH >= 22 || utcH < 6 ? 1.5 : 1.0);

  // Scale all counts by diurnal multiplier
  const TXN_COUNT   = Math.max(10, Math.round(randInt(TXN_MIN, TXN_MAX) * DIURNAL));
  const ORDER_COUNT = Math.max(2,  Math.round(randInt(ORDER_MIN, ORDER_MAX) * DIURNAL));
  const ALERT_COUNT = Math.max(1,  Math.round(randInt(ALERT_MIN, ALERT_MAX) * (0.40 + DIURNAL * 0.65)));

  const events = [];

  // ─── SECTION 1: Primary Transactions ─────────────────────────────────────
  // [REPLACE] Rename event types to match the customer domain, e.g.:
  //   "payment.authorization.completed", "order.placed", "booking.confirmed"
  const txnTimes = distribute(afterMs(start, 60000), afterMs(now, -60000), TXN_COUNT, 0.20);

  for (let i = 0; i < txnTimes.length; i++) {
    const ts      = txnTimes[i];
    const envIdx  = chooseWeighted([0, 1], ENV_WEIGHTS);
    const env     = ENVIRONMENTS[envIdx];
    const product = chooseWeighted(PRODUCTS, PROD_WEIGHTS);
    const channel = chooseWeighted(CHANNELS, CHAN_WEIGHTS);
    const segment = chooseWeighted(SEGMENTS, SEG_WEIGHTS);
    const amount  = Number(randFloat(10, 5000).toFixed(2)); // [REPLACE] range

    const isSysErr  = Math.random() < ERROR_RATE;
    const isBizDecl = !isSysErr && Math.random() < effectiveDeclineRate;
    const isFailed  = isSysErr || isBizDecl;
    const latency   = Math.round(randFloat(50, 300) * loadFactor * (isFailed ? 4 : 1));

    const extra = {
      "transaction.id":          randomId("TXN-", 10),
      "customer.id":             randomId("CUST-", 8),
      "product":                 product,
      "channel":                 channel,
      "customer.segment":        segment,
      "transaction.amount":      amount,
      "currency":                "USD", // [REPLACE]
      "response.time.ms":        latency,
      "environment":             env.name,
      "processing.location":     env.location,
      "geo.location.latitude":   env.lat,
      "geo.location.longitude":  env.lon,
      "hour.of.day":             utcH,
      "day.of.week":             dayName,
      "is.weekend":              isWeekend,
      "diurnal.multiplier":      Math.round(DIURNAL * 100) / 100
    };
    if (isFailed) {
      extra["failure.reason"]   = isSysErr
        ? choose(SYS_ERROR_REASONS)
        : chooseWeighted(BIZ_DECLINE_REASONS, BIZ_DECLINE_WEIGHTS);
      extra["failure.category"] = isSysErr ? "system" : "business";
    }

    // [REPLACE] event type names
    const etype = isFailed ? "transaction.failed" : "transaction.completed";
    events.push(makeEvent(EVENT_PROVIDER, etype, ts, extra, now));
  }

  // ─── SECTION 2: Secondary Business Events ────────────────────────────────
  // [REPLACE] This section models a secondary flow (e.g. account opens,
  //   bookings, subscriptions, card issuance). Rename fields accordingly.
  const orderTimes = distribute(afterMs(start, 180000), afterMs(now, -180000), ORDER_COUNT, 0.15);

  for (let i = 0; i < orderTimes.length; i++) {
    const ts      = orderTimes[i];
    const envIdx  = chooseWeighted([0, 1], ENV_WEIGHTS);
    const env     = ENVIRONMENTS[envIdx];
    const product = chooseWeighted(PRODUCTS, PROD_WEIGHTS);
    const channel = chooseWeighted(CHANNELS, CHAN_WEIGHTS);
    const segment = chooseWeighted(SEGMENTS, SEG_WEIGHTS);

    events.push(makeEvent(EVENT_PROVIDER, "secondary.event.completed", ts, { // [REPLACE] event type
      "event.id":                randomId("EVT-", 8),
      "customer.id":             randomId("CUST-", 8),
      "product":                 product,
      "channel":                 channel,
      "customer.segment":        segment,
      "environment":             env.name,
      "processing.location":     env.location,
      "geo.location.latitude":   env.lat,
      "geo.location.longitude":  env.lon,
      "hour.of.day":             utcH,
      "day.of.week":             dayName,
      "is.weekend":              isWeekend
    }, now));
  }

  // ─── SECTION 3: Platform / Infrastructure Alerts ─────────────────────────
  // Models operational noise (alert fatigue use case).
  // ALERT_COUNT scales with DIURNAL so peak hours show more alerts.
  const alertTimes = distribute(afterMs(start, 60000), afterMs(now, -60000), ALERT_COUNT, 0.12);

  for (let i = 0; i < alertTimes.length; i++) {
    const ts        = alertTimes[i];
    const envIdx    = chooseWeighted([0, 1], ENV_WEIGHTS);
    const env       = ENVIRONMENTS[envIdx];
    const alertType = chooseWeighted(ALERT_TYPES, ALERT_WEIGHTS);
    const severity  = chooseWeighted(SEVERITIES, SEV_WEIGHTS);
    const component = choose(COMPONENTS);
    const resMins   = severity === "critical" ? randInt(5, 30) : (severity === "high" ? randInt(10, 60) : randInt(15, 120));
    const autoResolved = (severity === "low" || severity === "medium") ? Math.random() > 0.3 : Math.random() > 0.7;

    events.push(makeEvent(EVENT_PROVIDER, "platform.alert.raised", ts, {
      "alert.id":                randomId("ALT-", 8),
      "alert.type":              alertType,
      "severity":                severity,
      "component":               component,
      "environment":             env.name,
      "processing.location":     env.location,
      "resolution.time.minutes": resMins,
      "auto.resolved":           autoResolved,
      "geo.location.latitude":   env.lat,
      "geo.location.longitude":  env.lon,
      "hour.of.day":             utcH,
      "day.of.week":             dayName,
      "is.weekend":              isWeekend
    }, now));
  }

  // ─── ADD SECTIONS 4, 5 … as needed ───────────────────────────────────────
  // Copy the pattern from sections 1–3 above. Common additions:
  //   Section 4: Fraud / risk alerts
  //   Section 5: Customer satisfaction / NPS surveys
  //   Section 6: Batch job completions (settlement, reporting)
  //   Section 7: User session / engagement events

  // ─── INGEST ──────────────────────────────────────────────────────────────
  const totals = countBy(events, e => e["event.type"]);
  const batches = [];

  for (let i = 0; i < events.length; i += CHUNK) {
    const batch = events.slice(i, i + CHUNK);
    const res = await fetch("/platform/classic/environment-api/v2/bizevents/ingest", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(batch)
    });

    let text = "";
    try { text = await res.text(); } catch (_) {}

    if (!res.ok) {
      console.error(`Ingest failed batch ${i}–${i + batch.length - 1}: HTTP ${res.status} ${text}`);
      throw new Error(`BizEvents ingest failed: HTTP ${res.status}`);
    }
    batches.push({ range: `${i}–${i + batch.length - 1}`, status: res.status });
  }

  return {
    client:    CLIENT_NAME,
    totals,
    batches,
    sample:    events.slice(0, 2),
    meta: {
      totalEvents:        events.length,
      utcHour:            utcH,
      dayName,
      isWeekend,
      diurnalMultiplier:  Math.round(DIURNAL * 100) / 100,
      loadFactor,
      transactions:       TXN_COUNT,
      secondaryEvents:    ORDER_COUNT,
      platformAlerts:     ALERT_COUNT
    }
  };
}
